using System;

class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty environment variables are now supported
        // and no longer treated as unset. GetEnvironmentVariable("MY_FLAG")
        // returns "" instead of null when the variable is set but empty.
        // Use string.IsNullOrEmpty only when empty and unset should be equivalent.
        // Here we must distinguish "not set" (null) from "explicitly empty" (""),
        // so the null check is correct.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val == null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

