using System.IO.Compression;
using System.Text;

class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry names/comments now respect the
        // UTF-8 flag (EFS bit 11). In .NET 8, non-ASCII names were written using
        // the system default encoding. In .NET 9, the UTF-8 flag is set and names
        // are encoded as UTF-8, which the legacy Java consumer cannot read.
        //
        // Fix: open the archive with an explicit Shift-JIS entryNameEncoding so
        // the UTF-8 flag is NOT set and filenames are encoded in Shift-JIS.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

